def fit_hierarchical_models_manual(X_blocks: List[np.ndarray], y: np.ndarray, 
                                 block_names: List[str]) -> Dict[str, Any]:
    """
    Manual hierarchical regression implementation.
    
    Parameters
    ----------
    X_blocks : List of arrays
        [X_block1, X_block2, ...] where each is (n_samples, n_features_block)
    y : array
        Outcome variable (n_samples,)
    block_names : List of str
        ['controls', 'dass_predictors', ...]
    
    Returns
    -------
    Dict with:
        models: List of fitted statsmodels OLS results
        summary: DataFrame with model comparison results
        delta_r2_details: Dict with F-test details for incremental R²
    """
    models = []
    model_summaries = []
    
    # Cumulative predictors
    X_cumulative = None
    prev_r2 = 0.0
    
    for i, (X_block, block_name) in enumerate(zip(X_blocks, block_names)):
        # Add current block to cumulative predictors
        if X_cumulative is None:
            X_cumulative = X_block
        else:
            X_cumulative = np.column_stack([X_cumulative, X_block])
        
        # Fit model with cumulative predictors
        X_with_const = sm.add_constant(X_cumulative)
        model = sm.OLS(y, X_with_const).fit()
        models.append(model)
        
        # Extract model information
        curr_r2 = model.rsquared
        adj_r2 = model.rsquared_adj
        f_stat = model.fvalue
        f_pval = model.f_pvalue
        df1 = model.df_model
        df2 = model.df_resid
        
        # Calculate ΔR²
        if i == 0:
            delta_r2 = curr_r2  # First model vs null
        else:
            delta_r2 = curr_r2 - prev_r2
        
        # Model name
        if i == 0:
            model_name = f"Model {i+1}: {block_name}"
        else:
            model_name = f"Model {i+1}: " + " + ".join(block_names[:i+1])
        
        # Add to summary
        model_summaries.append({
            'model': model_name,
            'R2': curr_r2,
            'adj_R2': adj_r2,
            'F_stat': f_stat,
            'df1': df1,
            'df2': df2,
            'p_value': f_pval,
            'delta_R2': delta_r2
        })
        
        prev_r2 = curr_r2
    
    # Create summary DataFrame
    summary_df = pd.DataFrame(model_summaries)
    
    # Calculate F-test for ΔR² (for last block only - the increment of interest)
    delta_r2_details = {}
    if len(models) >= 2:
        # F-test for incremental R² of final block
        model_reduced = models[-2]  # Previous model
        model_full = models[-1]    # Full model
        
        n = len(y)
        r2_reduced = model_reduced.rsquared
        r2_full = model_full.rsquared
        k_reduced = model_reduced.df_model
        k_full = model_full.df_model
        k_increment = k_full - k_reduced
        
        delta_r2_value = r2_full - r2_reduced
        
        if delta_r2_value > 0 and (1 - r2_full) > 0:
            f_increment = (delta_r2_value / k_increment) / ((1 - r2_full) / (n - k_full - 1))
            p_increment = 1 - stats.f.cdf(f_increment, k_increment, n - k_full - 1)
        else:
            f_increment = 0.0
            p_increment = 1.0
        
        delta_r2_details = {
            'delta_r2': delta_r2_value,
            'f_statistic': f_increment,
            'p_value': p_increment,
            'df_numerator': k_increment,
            'df_denominator': n - k_full - 1
        }
    
    return {
        'models': models,
        'summary': summary_df,
        'delta_r2_details': delta_r2_details
    }

def bootstrap_delta_r2(X_blocks: List[np.ndarray], y: np.ndarray, 
                      block_names: List[str], n_bootstrap: int = 1000, 
                      random_seed: int = 42) -> Dict[str, Any]:
    """
    Bootstrap confidence intervals for incremental ΔR².
    
    Parameters
    ----------
    X_blocks : List of arrays
        Predictor blocks
    y : array  
        Outcome variable
    block_names : List of str
        Block names
    n_bootstrap : int
        Number of bootstrap samples
    random_seed : int
        Random seed for reproducibility
        
    Returns
    -------
    Dict with bootstrap results and confidence intervals
    """
    np.random.seed(random_seed)
    n_samples = len(y)
    
    bootstrap_deltas = []
    successful_iterations = 0
    
    for i in range(n_bootstrap):
        try:
            # Bootstrap sample with replacement
            bootstrap_indices = np.random.choice(n_samples, size=n_samples, replace=True)
            
            # Create bootstrap samples
            y_boot = y[bootstrap_indices]
            X_blocks_boot = [X_block[bootstrap_indices] for X_block in X_blocks]
            
            # Fit hierarchical models on bootstrap sample
            boot_results = fit_hierarchical_models_manual(X_blocks_boot, y_boot, block_names)
            
            # Extract ΔR² 
            if len(boot_results['models']) >= 2:
                r2_reduced = boot_results['models'][-2].rsquared
                r2_full = boot_results['models'][-1].rsquared
                delta_r2_boot = r2_full - r2_reduced
                
                bootstrap_deltas.append(delta_r2_boot)
                successful_iterations += 1
            
        except:
            # Skip failed bootstrap samples (convergence issues, etc.)
            pass
        
        # Progress logging every 200 iterations
        if (i + 1) % 200 == 0:
            log(f"[BOOTSTRAP] Completed {i+1}/{n_bootstrap} iterations ({successful_iterations} successful)")
    
    # Compute confidence intervals
    if len(bootstrap_deltas) > 50:  # Minimum for reasonable CI
        bootstrap_deltas = np.array(bootstrap_deltas)
        ci_lower = np.percentile(bootstrap_deltas, 2.5)
        ci_upper = np.percentile(bootstrap_deltas, 97.5)
        point_estimate = np.mean(bootstrap_deltas)
        
        return {
            'bootstrap_deltas': bootstrap_deltas,
            'ci_lower': ci_lower,
            'ci_upper': ci_upper,
            'point_estimate': point_estimate,
            'successful_iterations': successful_iterations,
            'total_iterations': n_bootstrap
        }
    else:
        return {
            'bootstrap_deltas': [],
            'ci_lower': np.nan,
            'ci_upper': np.nan,
            'point_estimate': np.nan,
            'successful_iterations': successful_iterations,
            'total_iterations': n_bootstrap
        }

